  const VALUE_ENGINEERING_NOTES=[{title:'Partition optimization',detail:'Replace selected internal 150 mm block partitions with insulated drywall in non-wet rooms to reduce dead load, improve programme, and free up service routing. Typical savings: 12 to 18 percent on partition scope with faster installation.',impact:'Programme and structural load reduction'},{title:'Standardize wet area modules',detail:'Use repeated bathroom and pantry layouts floor-wise so drainage drops, waterproofing upstands, and accessory packages remain standardized. This improves subcontractor productivity and reduces design coordination clashes.',impact:'Reduces material wastage and labour variability'},{title:'Facade rationalization',detail:'Limit glazing module types and align mullion bays with structural grid. Fewer extrusion profiles and repeated panel sizes reduce procurement risk and simplify maintenance planning.',impact:'Improves procurement and long-term replacement strategy'},{title:'Integrated MEP coordination',detail:'Lock ceiling zone strategy room-wise before tender. Coordinated HVAC, electrical containment, and sprinklers reduce late rerouting and oversize ceiling voids.',impact:'Avoids rework and protects architectural finishes'},{title:'Solar and electrical integration',detail:'Where solar scope is selected, coordinate inverter rooms, containment, and roof access with primary electrical packages rather than tendering them separately. This avoids duplicated preliminaries and temporary works.',impact:'Cleaner package strategy and lower interface risk'}];
