  function getDefaultState(){return{project:{name:'Untitled Project',client:'',location:'Eastern Province',region:'saudi',projectType:'residential',buildingCode:'SBC304',grossFloorArea:0,floorsCount:2,roomsPerFloor:3,siteArea:600,facadeFactor:.72,solarRoofShare:.4,industrialCoverage:.2,excavationDepth:1.2,backfillRatio:.65,contingencyPct:10,taxPct:5,notes:''},selectedScopes:Object.assign({},DEFAULT_SCOPE_SELECTION),floors:[{id:uid('floor'),name:'Ground Floor',level:1,rooms:[buildRoom('living','Living Room',6.2,4.8,3.4,2,3),buildRoom('kitchen','Kitchen',4.4,3.6,3.2,1,2),buildRoom('bathroom','Powder Room',2.1,1.8,3,1,1)]},{id:uid('floor'),name:'First Floor',level:2,rooms:[buildRoom('bedroom','Master Bedroom',5.5,4.6,3.2,1,2),buildRoom('bathroom','Master Bathroom',3.1,2.5,3,1,1),buildRoom('bedroom','Bedroom 2',4.2,3.8,3.1,1,2)]}],boq:{items:[],totals:{}},lastUpdated:new Date().toISOString()};}
