  function computeRoomMetrics(room){const floorArea=room.length*room.width,perimeter=2*(room.length+room.width),grossWallArea=perimeter*room.height,openingArea=room.doors*1.9+room.windows*1.8,netWallArea=Math.max(grossWallArea-openingArea,floorArea*1.6),wetArea=floorArea*room.wetFactor;return{floorArea,perimeter,grossWallArea,netWallArea,openingArea,wetArea};}
  function getProjectMetrics(state){const rooms=state.floors.flatMap(f=>f.rooms.map(r=>({floor:f,room:r})));let totalFloorArea=0,facadeArea=0;rooms.forEach(({room})=>{const m=computeRoomMetrics(room);totalFloorArea+=m.floorArea;if(room.includeFacade)facadeArea+=Math.max(room.windows*2.6,m.perimeter*room.height*.18);});return{totalFloorArea,siteArea:Number(state.project.siteArea||0),facadeArea:Math.max(facadeArea,totalFloorArea*Number(state.project.facadeFactor||.72)),roofSolarArea:totalFloorArea*Number(state.project.solarRoofShare||.4),industrialArea:totalFloorArea*Number(state.project.industrialCoverage||.2),externalWorksArea:Math.max(Number(state.project.siteArea||0)-totalFloorArea,totalFloorArea*.35),excavationVolume:totalFloorArea*Number(state.project.excavationDepth||1.2)*.42};}
  function getProjectMultiplier(projectType,categoryKey){const table={residential:{mep:1,finishes:1,facade:1,industrialSystems:.1,solarSystems:.7,interiorFitout:1,preliminaries:1,default:1},commercial_office:{mep:1.16,finishes:1.08,facade:1.12,industrialSystems:.35,solarSystems:.75,interiorFitout:1.18,preliminaries:1.08,default:1.06},commercial_retail:{mep:1.1,finishes:1.22,facade:1.08,industrialSystems:.28,solarSystems:.65,interiorFitout:1.28,preliminaries:1.08,default:1.08},mixed_use:{mep:1.14,finishes:1.16,facade:1.1,industrialSystems:.2,solarSystems:.82,interiorFitout:1.18,preliminaries:1.1,default:1.1},industrial:{mep:1.18,finishes:.72,facade:.68,industrialSystems:1.42,solarSystems:.92,interiorFitout:.6,preliminaries:1.12,default:.95},hospitality:{mep:1.22,finishes:1.32,facade:1.2,industrialSystems:.18,solarSystems:.76,interiorFitout:1.34,preliminaries:1.14,default:1.18},healthcare:{mep:1.28,finishes:1.2,facade:1.05,industrialSystems:.42,solarSystems:.74,interiorFitout:1.16,preliminaries:1.16,default:1.2}};const row=table[projectType]||table.residential;return row[categoryKey]||row.default||1;}
  function computeFormulaQty(formula,context){const {room,projectMetrics,roomMetrics,state}=context,totalArea=projectMetrics.totalFloorArea;switch(formula){case'siteArea':return projectMetrics.siteArea;case'excavation':return projectMetrics.excavationVolume;case'backfill':return projectMetrics.excavationVolume*Number(state.project.backfillRatio||.65);case'blinding':return totalArea*.055;case'foundationConcrete':return totalArea*.18;case'foundationRebar':return totalArea*24;case'foundationFormwork':return totalArea*.88;case'slabConcrete':return roomMetrics.floorArea*.16;case'slabRebar':return roomMetrics.floorArea*18;case'frameConcrete':return roomMetrics.floorArea*.07;case'externalWallArea':return roomMetrics.netWallArea*.36;case'internalPartitionArea':return roomMetrics.netWallArea*.72;case'drywallArea':return room.partitionType.toLowerCase().includes('drywall')?roomMetrics.netWallArea*.7:0;case'floorArea':return roomMetrics.floorArea;case'finishFloorArea':return roomMetrics.floorArea;case'finishWallArea':return roomMetrics.netWallArea*(room.wallFinish.toLowerCase().includes('tile')?1:.45);case'paintArea':return room.wallFinish.toLowerCase().includes('paint')?roomMetrics.netWallArea+roomMetrics.floorArea:roomMetrics.netWallArea*.5;case'ceilingArea':return roomMetrics.floorArea;case'wetArea':return roomMetrics.wetArea+(room.plumbingClass==='Full'?roomMetrics.netWallArea*.35:0);case'doors':return room.doors;case'windows':return room.windows;case'facadeArea':return projectMetrics.facadeArea;case'externalWorksArea':return projectMetrics.externalWorksArea;case'electricalArea':return room.includeMEP?roomMetrics.floorArea*(room.electricalClass==='Commercial'?1.12:room.electricalClass==='Enhanced'?1.06:1):0;case'plumbingArea':return room.includeMEP&&room.plumbingClass!=='None'?roomMetrics.floorArea*(room.plumbingClass==='Full'?1:.45):0;case'hvacArea':return room.includeMEP?roomMetrics.floorArea*(room.hvacType.toLowerCase().includes('vrf')?1.2:room.hvacType.toLowerCase().includes('split')?1:.72):0;case'fireArea':return room.includeMEP?roomMetrics.floorArea*.85:0;case'industrialArea':return projectMetrics.industrialArea;case'roofSolarArea':return projectMetrics.roofSolarArea;case'fitoutArea':return roomMetrics.floorArea*((room.typeKey==='office'||room.typeKey==='retail')?1:.42);case'preliminaries':return RATE_BOOK.preliminaries.prices[state.project.region||'saudi'];default:return 0;}}
  function buildSpecText(itemKey,room){if(!room)return'Project-wide quantity';const specs={floorFinish:room.finishFloor,wallFinish:room.wallFinish,paintSystem:room.wallFinish,ceilingFinish:room.ceilingFinish,wetAreaWaterproofing:'Waterproofing to wet floor and wet wall zones',doors:'Room-wise selected door set',windows:'Room-wise selected window set',externalBlock:'External wall type coordinated with room envelope',internalBlock:room.partitionType,drywallPartitions:room.partitionType,electrical:room.electricalClass+' electrical density',plumbing:room.plumbingClass+' plumbing distribution',hvac:room.hvacType,fireProtection:'Fire protection coordinated with room occupancy',joinery:'Room-wise fit-out and joinery package',slabConcrete:'Concrete quantities allocated proportionally to room floor plate',slabRebar:'Rebar tonnage derived from room floor plate',columnsBeams:'Frame allowance allocated by room floor plate'};return specs[itemKey]||'Room-wise specification';}
  function buildBOQ(state){const region=state.project.region,projectType=state.project.projectType,projectMetrics=getProjectMetrics(state),items=[];let itemNo=1;CATEGORY_LIBRARY.forEach(category=>{if(!state.selectedScopes[category.key])return;if(category.group==='project'){category.items.forEach(item=>{let qty=computeFormulaQty(item.formula,{state,projectMetrics,categoryKey:category.key});if(item.rateCode!=='preliminaries')qty*=getProjectMultiplier(projectType,category.key);const rate=getRateValue(item.rateCode,region),amount=item.rateCode==='preliminaries'?0:qty*rate;items.push({id:uid('line'),no:String(itemNo++).padStart(3,'0'),category:category.title,floor:'Project-wide',room:'Common',description:item.label,specification:'Project-wide scope derived from selected floors, rooms, and project inputs',qty:roundQty(qty,item.unit),unit:item.unit,rate,amount:roundMoney(amount),rateCode:item.rateCode});});}
      if(category.group==='room'){state.floors.forEach(floor=>{floor.rooms.forEach(room=>{const roomMetrics=computeRoomMetrics(room);category.items.forEach(item=>{let qty=computeFormulaQty(item.formula,{state,room,roomMetrics,projectMetrics,categoryKey:category.key});if(!qty)return;qty*=getProjectMultiplier(projectType,category.key);const rate=getRateValue(item.rateCode,region),amount=qty*rate;items.push({id:uid('line'),no:String(itemNo++).padStart(3,'0'),category:category.title,floor:floor.name,room:room.name,description:item.label,specification:buildSpecText(item.key,room),qty:roundQty(qty,item.unit),unit:item.unit,rate,amount:roundMoney(amount),rateCode:item.rateCode});});});});}}
    );
    const directTotal=items.reduce((s,i)=>s+Number(i.amount||0),0),prelimPct=getRateValue('preliminaries',region);
    if(state.selectedScopes.preliminaries){const prelimAmount=directTotal*(prelimPct/100)*getProjectMultiplier(projectType,'preliminaries');items.push({id:uid('line'),no:String(itemNo++).padStart(3,'0'),category:'Preliminaries',floor:'Project-wide',room:'Common',description:'Preliminaries, temporary facilities, mobilization and supervision',specification:'Applied as commercial percentage to direct construction scope',qty:roundQty(prelimPct,'pct'),unit:'%',rate:directTotal,amount:roundMoney(prelimAmount),rateCode:'preliminaries'});}
    const totalsByCategory={};items.forEach(i=>totalsByCategory[i.category]=(totalsByCategory[i.category]||0)+Number(i.amount||0));
    const totalBeforeTax=items.reduce((s,i)=>s+Number(i.amount||0),0),contingencyAmount=totalBeforeTax*(Number(state.project.contingencyPct||0)/100),subtotalWithContingency=totalBeforeTax+contingencyAmount,taxAmount=subtotalWithContingency*(Number(state.project.taxPct||0)/100),grandTotal=subtotalWithContingency+taxAmount,floorArea=getProjectMetrics(state).totalFloorArea;
    return{items,totals:{byCategory:totalsByCategory,totalBeforeTax:roundMoney(totalBeforeTax),contingencyAmount:roundMoney(contingencyAmount),taxAmount:roundMoney(taxAmount),grandTotal:roundMoney(grandTotal),floorArea:roundMoney(floorArea),costPerSqm:floorArea?roundMoney(grandTotal/floorArea):0}};
  }
  function buildCommercialSummary(state){const boq=state.boq&&state.boq.items&&state.boq.items.length?state.boq:buildBOQ(state),benchmark=BENCHMARKS[state.project.region]?.[state.project.projectType]||0;return{benchmark,delta:boq.totals.costPerSqm-benchmark};}
  function buildMaterialTakeoff(state){const boq=state.boq&&state.boq.items&&state.boq.items.length?state.boq:buildBOQ(state),map={concrete:'Concrete',rebar:'Reinforcement',blockwork:'Blockwork and masonry',drywall:'Drywall and partitions',floorFinish:'Floor finishes',wallFinish:'Wall finishes',paint:'Paint systems',ceiling:'Ceilings',waterproofing:'Waterproofing',doors:'Doors',windows:'Windows',facade:'Facade',paving:'External works',electrical:'Electrical',plumbing:'Plumbing',hvac:'HVAC',fireProtection:'Fire protection',industrial:'Industrial systems',solar:'Solar systems',joinery:'Joinery and fit-out',siteClearing:'Site preparation',surveying:'Site preparation',excavation:'Earthworks',backfilling:'Earthworks',blinding:'Substructure',formwork:'Formwork',preliminaries:'Commercial'},rows={};boq.items.forEach(item=>{const group=map[item.rateCode]||item.category;if(!rows[group])rows[group]={bucket:group,qty:0,amount:0,unit:item.unit};rows[group].qty+=Number(item.qty||0);rows[group].amount+=Number(item.amount||0);});return Object.values(rows).sort((a,b)=>b.amount-a.amount);}
  function buildTradePackages(state){const boq=state.boq&&state.boq.items&&state.boq.items.length?state.boq:buildBOQ(state),grouped={};boq.items.forEach(item=>{if(!grouped[item.category])grouped[item.category]=[];grouped[item.category].push(item);});return Object.entries(grouped).map(([category,items])=>({category,total:items.reduce((s,i)=>s+Number(i.amount||0),0),items:items.sort((a,b)=>a.floor.localeCompare(b.floor)||a.room.localeCompare(b.room))})).sort((a,b)=>b.total-a.total);}
